import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as s,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Добавление канала Yandex","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/yandex.md","filePath":"ru-RU/upload/yandex.md","lastUpdated":1781962217000}'),l={name:"ru-RU/upload/yandex.md"};function c(p,e,h,x,m,b){return s(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="добавление-канала-yandex" tabindex="-1">Добавление канала Yandex <a class="header-anchor" href="#добавление-канала-yandex" aria-label="Permalink to &quot;Добавление канала Yandex&quot;">​</a></h1><h2 id="что-подготовить-сначала" tabindex="-1">Что подготовить сначала <a class="header-anchor" href="#что-подготовить-сначала" aria-label="Permalink to &quot;Что подготовить сначала&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Что нужно</th><th>Зачем это нужно</th></tr></thead><tbody><tr><td>Аккаунт Yandex</td><td>Для входа и авторизации Yandex Disk</td></tr><tr><td>Yandex OAuth app</td><td>Для получения <code>Client ID</code> и <code>Client Secret</code></td></tr><tr><td>Ваш домен ImgBed</td><td>Для OAuth redirect URI</td></tr><tr><td>Доступное хранилище Yandex Disk</td><td>Фактическое место хранения файлов</td></tr></tbody></table><h2 id="настроика" tabindex="-1">Настройка <a class="header-anchor" href="#настроика" aria-label="Permalink to &quot;Настройка&quot;">​</a></h2><h3 id="шаг-1-создаите-yandex-oauth-app" tabindex="-1">Шаг 1. Создайте Yandex OAuth app <a class="header-anchor" href="#шаг-1-создаите-yandex-oauth-app" aria-label="Permalink to &quot;Шаг 1. Создайте Yandex OAuth app&quot;">​</a></h3><ol><li>Откройте страницу создания Yandex OAuth app:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>Если вас перенаправит на вход, сначала войдите в аккаунт Yandex.</li><li>Создайте новый app.</li><li>Дайте app понятное имя, например <code>imgbed-yandex</code>.</li><li>Найдите настройки callback или redirect URL.</li><li>Введите:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="шаг-2-проверьте-permissions" tabindex="-1">Шаг 2. Проверьте permissions <a class="header-anchor" href="#шаг-2-проверьте-permissions" aria-label="Permalink to &quot;Шаг 2. Проверьте permissions&quot;">​</a></h3><p>Для текущей интеграции ImgBed с Yandex оставьте эти четыре permissions в <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Назначение</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Позволяет ImgBed хранить файлы в app folder</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Читает файлы и download links</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Загружает файлы, создает папки и удаляет файлы</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Читает квоту диска и использованный объем</td></tr></tbody></table><p>Если вы также видите эти permissions в <code>Yandex ID API</code>, они необязательны:</p><table tabindex="0"><thead><tr><th>Текст permission</th><th>Рекомендация</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Необязательно</td></tr><tr><td><code>Access to email address</code></td><td>Необязательно</td></tr></tbody></table><p>Основные функции загрузки, скачивания, удаления и квот в основном зависят от четырех permissions <code>Yandex.Disk REST API</code>, перечисленных выше.</p><p><img src="'+t+'" alt="Настройка permissions Yandex Disk" loading="lazy"></p><h3 id="шаг-3-скопируите-credentials-app" tabindex="-1">Шаг 3. Скопируйте credentials app <a class="header-anchor" href="#шаг-3-скопируите-credentials-app" aria-label="Permalink to &quot;Шаг 3. Скопируйте credentials app&quot;">​</a></h3><p>После создания app скопируйте:</p><table tabindex="0"><thead><tr><th>Поле Yandex</th><th>Поле ImgBed</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Запись Client ID и Secret" loading="lazy"></p><h3 id="шаг-4-заполните-канал-yandex" tabindex="-1">Шаг 4. Заполните канал Yandex <a class="header-anchor" href="#шаг-4-заполните-канал-yandex" aria-label="Permalink to &quot;Шаг 4. Заполните канал Yandex&quot;">​</a></h3><p>В настройках загрузки выберите <code>Yandex</code> и заполните:</p><table tabindex="0"><thead><tr><th>Поле ImgBed</th><th>Что ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Понятное имя, например <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td><code>Client ID</code> Yandex app</td></tr><tr><td>Client Secret</td><td><code>Client Secret</code> Yandex app</td></tr><tr><td>Refresh Token</td><td>Пока оставьте пустым</td></tr><tr><td>Root directory</td><td>Необязательно. По умолчанию <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+d+'" alt="Редактирование конфигурации канала" loading="lazy"></p><h3 id="шаг-5-получите-refresh-token" tabindex="-1">Шаг 5. Получите Refresh Token <a class="header-anchor" href="#шаг-5-получите-refresh-token" aria-label="Permalink to &quot;Шаг 5. Получите Refresh Token&quot;">​</a></h3><ol><li>В ImgBed нажмите <code>Get Token</code>.</li><li>Войдите в Yandex-аккаунт, который хотите подключить.</li><li>Подтвердите запрос авторизации.</li><li>На callback-странице появится <code>Refresh Token</code>.</li><li>Скопируйте его.</li><li>Вернитесь в ImgBed и вставьте его в поле <code>Refresh Token</code>.</li></ol><p><img src="'+n+`" alt="Копирование refresh token после авторизации" loading="lazy"></p><h3 id="шаг-6-сохраните-канал" tabindex="-1">Шаг 6. Сохраните канал <a class="header-anchor" href="#шаг-6-сохраните-канал" aria-label="Permalink to &quot;Шаг 6. Сохраните канал&quot;">​</a></h3><p>Когда все поля заполнены, сохраните канал.</p><h2 id="короткии-сценарии" tabindex="-1">Короткий сценарий <a class="header-anchor" href="#короткии-сценарии" aria-label="Permalink to &quot;Короткий сценарий&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Открыть Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Создать app</span></span>
<span class="line"><span>-&gt; Добавить https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Проверить permissions Yandex Disk</span></span>
<span class="line"><span>-&gt; Скопировать Client ID и Client Secret</span></span>
<span class="line"><span>-&gt; Ввести Client ID / Client Secret в ImgBed</span></span>
<span class="line"><span>-&gt; Нажать Get Token</span></span>
<span class="line"><span>-&gt; Скопировать Refresh Token с callback-страницы</span></span>
<span class="line"><span>-&gt; Вставить его обратно в ImgBed и сохранить</span></span></code></pre></div><h2 id="ссылки" tabindex="-1">Ссылки <a class="header-anchor" href="#ссылки" aria-label="Permalink to &quot;Ссылки&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const y=o(l,[["render",c]]);export{g as __pageData,y as default};
